CREATE MATERIALIZED VIEW public.department_drafts_mv AS
 WITH draft_links AS (
         SELECT department_drafts_departments_connection.draft_id,
            'departments'::text AS resource_type,
            department_drafts_departments_connection.departments_id AS resource_id
           FROM public.department_drafts_departments_connection
          WHERE (department_drafts_departments_connection.active = true)
        UNION ALL
         SELECT department_drafts_descriptions_connection.draft_id,
            'descriptions'::text AS resource_type,
            department_drafts_descriptions_connection.descriptions_id AS resource_id
           FROM public.department_drafts_descriptions_connection
          WHERE (department_drafts_descriptions_connection.active = true)
        UNION ALL
         SELECT department_drafts_flags_connection.draft_id,
            'flags'::text AS resource_type,
            department_drafts_flags_connection.flags_id AS resource_id
           FROM public.department_drafts_flags_connection
          WHERE (department_drafts_flags_connection.active = true)
        UNION ALL
         SELECT department_drafts_names_connection.draft_id,
            'names'::text AS resource_type,
            department_drafts_names_connection.names_id AS resource_id
           FROM public.department_drafts_names_connection
          WHERE (department_drafts_names_connection.active = true)
        UNION ALL
         SELECT department_drafts_settings_connection.draft_id,
            'settings'::text AS resource_type,
            department_drafts_settings_connection.settings_id AS resource_id
           FROM public.department_drafts_settings_connection
          WHERE (department_drafts_settings_connection.active = true)
        )
 SELECT d.id AS draft_id,
    d.created_at,
    d.updated_at,
    d.version,
    d.generated,
    d.mcp,
    d.active,
    d.group_id,
    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'departments'::text)), ARRAY[]::uuid[]) AS department_ids,
    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'descriptions'::text)), ARRAY[]::uuid[]) AS description_ids,
    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'flags'::text)), ARRAY[]::uuid[]) AS flag_ids,
    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'names'::text)), ARRAY[]::uuid[]) AS name_ids,
    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'settings'::text)), ARRAY[]::uuid[]) AS settings_ids
   FROM (public.department_drafts_entry d
     LEFT JOIN draft_links l ON ((l.draft_id = d.id)))
  GROUP BY d.id, d.created_at, d.updated_at, d.version, d.generated, d.mcp, d.active, d.group_id
